import{_ as a,c as e,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Modo Ultrawork: Ative Todos os Recursos com Um Comando","description":"Aprenda o modo Ultrawork do oh-my-opencode para ativar todos os recursos com um comando. Ativa agentes paralelos, conclusão forçada e sistema de Categoria + Skills.","frontmatter":{"title":"Modo Ultrawork: Ative Todos os Recursos com Um Comando","sidebarTitle":"Modo Ultrawork","subtitle":"Modo Ultrawork: Ative Todos os Recursos com Um Comando","description":"Aprenda o modo Ultrawork do oh-my-opencode para ativar todos os recursos com um comando. Ativa agentes paralelos, conclusão forçada e sistema de Categoria + Skills.","tags":["ultrawork","tarefas em segundo plano","colaboração de agentes"],"prerequisite":["start-installation","start-sisyphus-orchestrator"],"order":30},"headers":[],"relativePath":"pt/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md","filePath":"pt/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"}'),s={name:"pt/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"};function i(d,o,n,l,c,u){return t(),e("div",null,[...o[0]||(o[0]=[r(`<h1 id="modo-ultrawork-ative-todos-os-recursos-com-um-comando" tabindex="-1">Modo Ultrawork: Ative Todos os Recursos com Um Comando <a class="header-anchor" href="#modo-ultrawork-ative-todos-os-recursos-com-um-comando" aria-label="Permalink to &quot;Modo Ultrawork: Ative Todos os Recursos com Um Comando&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><ul><li>Ativar todos os recursos avançados do oh-my-opencode com um único comando</li><li>Fazer com que múltiplos agentes de IA trabalhem em paralelo como uma equipe real</li><li>Evitar configurar manualmente múltiplos agentes e tarefas em segundo plano</li><li>Entender a filosofia de design e as melhores práticas do modo Ultrawork</li></ul><h2 id="seus-desafios-atuais" tabindex="-1">Seus Desafios Atuais <a class="header-anchor" href="#seus-desafios-atuais" aria-label="Permalink to &quot;Seus Desafios Atuais&quot;">​</a></h2><p>Você pode ter encontrado estas situações durante o desenvolvimento:</p><ul><li><strong>Muitos recursos, não sabe como usá-los</strong>: Você tem 10 agentes especializados, tarefas em segundo plano, ferramentas LSP, mas não sabe como ativá-los rapidamente</li><li><strong>Configuração manual necessária</strong>: Cada tarefa complexa requer especificar manualmente agentes, concorrência em segundo plano e outras configurações</li><li><strong>Colaboração de agentes ineficiente</strong>: Chamando agentes em série, desperdiçando tempo e custos</li><li><strong>Tarefas ficando presas no meio</strong>: Os agentes não têm motivação e restrições suficientes para completar as tarefas</li></ul><p>Isso tudo está afetando sua capacidade de liberar o verdadeiro poder do oh-my-opencode.</p><h2 id="conceito-central" tabindex="-1">Conceito Central <a class="header-anchor" href="#conceito-central" aria-label="Permalink to &quot;Conceito Central&quot;">​</a></h2><p><strong>Modo Ultrawork</strong> é o mecanismo de &quot;ativar tudo com um clique&quot; do oh-my-opencode.</p><div class="info custom-block"><p class="custom-block-title">O que é o Modo Ultrawork?</p><p>O Modo Ultrawork é um modo de trabalho especial acionado por uma palavra-chave. Quando seu prompt contém <code>ultrawork</code> ou sua abreviação <code>ulw</code>, o sistema ativa automaticamente todos os recursos avançados: tarefas em segundo plano paralelas, exploração profunda, conclusão forçada, colaboração multi-agente e muito mais.</p></div><h3 id="filosofia-de-design" tabindex="-1">Filosofia de Design <a class="header-anchor" href="#filosofia-de-design" aria-label="Permalink to &quot;Filosofia de Design&quot;">​</a></h3><p>O modo Ultrawork é baseado nos seguintes princípios centrais (do <a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer">Ultrawork Manifesto</a>):</p><table tabindex="0"><thead><tr><th>Princípio</th><th>Descrição</th></tr></thead><tbody><tr><td><strong>Intervenção humana é um sinal de falha</strong></td><td>Se você precisa corrigir constantemente a saída da IA, significa que há um problema no design do sistema</td></tr><tr><td><strong>Código indistinguível</strong></td><td>O código escrito pela IA deve ser indistinguível do código escrito por engenheiros seniores</td></tr><tr><td><strong>Minimizar carga cognitiva</strong></td><td>Você só precisa dizer &quot;o que fazer&quot;, os agentes são responsáveis por &quot;como fazer&quot;</td></tr><tr><td><strong>Previsível, consistente, delegável</strong></td><td>Os agentes devem ser tão estáveis e confiáveis quanto um compilador</td></tr></tbody></table><h3 id="mecanismo-de-ativacao" tabindex="-1">Mecanismo de Ativação <a class="header-anchor" href="#mecanismo-de-ativacao" aria-label="Permalink to &quot;Mecanismo de Ativação&quot;">​</a></h3><p>Quando o sistema detecta a palavra-chave <code>ultrawork</code> ou <code>ulw</code>:</p><ol><li><strong>Definir modo de precisão máxima</strong>: <code>message.variant = &quot;max&quot;</code></li><li><strong>Exibir notificação Toast</strong>: &quot;Modo Ultrawork Ativado - Precisão máxima engajada. Todos os agentes à sua disposição.&quot;</li><li><strong>Injetar instruções completas</strong>: Injeta 200+ linhas de instruções ULTRAWORK nos agentes, incluindo: <ul><li>Requer 100% de certeza antes de iniciar a implementação</li><li>Requer uso paralelo de tarefas em segundo plano</li><li>Força uso do sistema Categoria + Skills</li><li>Força verificação de conclusão (fluxo de trabalho TDD)</li><li>Proíbe qualquer desculpa do tipo &quot;não consigo fazer isso&quot;</li></ul></li></ol><h2 id="acompanhe" tabindex="-1">Acompanhe <a class="header-anchor" href="#acompanhe" aria-label="Permalink to &quot;Acompanhe&quot;">​</a></h2><h3 id="passo-1-acionar-o-modo-ultrawork" tabindex="-1">Passo 1: Acionar o Modo Ultrawork <a class="header-anchor" href="#passo-1-acionar-o-modo-ultrawork" aria-label="Permalink to &quot;Passo 1: Acionar o Modo Ultrawork&quot;">​</a></h3><p>Digite um prompt contendo a palavra-chave <code>ultrawork</code> ou <code>ulw</code> no OpenCode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ultrawork desenvolver uma API REST</span></span></code></pre></div><p>Ou de forma mais concisa:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ulw adicionar autenticação de usuário</span></span></code></pre></div><p><strong>Você deve ver</strong>:</p><ul><li>Uma notificação Toast aparece na interface: &quot;Modo Ultrawork Ativado&quot;</li><li>A resposta do agente começa com &quot;ULTRAWORK MODE ENABLED!&quot;</li></ul><h3 id="passo-2-observar-mudancas-no-comportamento-do-agente" tabindex="-1">Passo 2: Observar Mudanças no Comportamento do Agente <a class="header-anchor" href="#passo-2-observar-mudancas-no-comportamento-do-agente" aria-label="Permalink to &quot;Passo 2: Observar Mudanças no Comportamento do Agente&quot;">​</a></h3><p>Depois de ativar o modo Ultrawork, os agentes irão:</p><ol><li><p><strong>Exploração paralela da base de código</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;encontrar padrões de API existentes&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;encontrar infraestrutura de testes&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;librarian&quot;, prompt=&quot;encontrar melhores práticas de autenticação&quot;, background=true)</span></span></code></pre></div></li><li><p><strong>Chamar agente Plan para criar plano de trabalho</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(subagent_type=&quot;plan&quot;, prompt=&quot;criar plano detalhado baseado no contexto reunido&quot;)</span></span></code></pre></div></li><li><p><strong>Usar Categoria + Skills para executar tarefas</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(category=&quot;visual-engineering&quot;, load_skills=[&quot;frontend-ui-ux&quot;, &quot;playwright&quot;], ...)</span></span></code></pre></div></li></ol><p><strong>Você deve ver</strong>:</p><ul><li>Múltiplas tarefas em segundo plano rodando simultaneamente</li><li>Agentes chamando ativamente agentes especializados (Oracle, Librarian, Explore)</li><li>Planos de teste completos e decomposição de trabalho</li><li>Tarefas continuam executando até 100% completas</li></ul><h3 id="passo-3-verificar-conclusao-da-tarefa" tabindex="-1">Passo 3: Verificar Conclusão da Tarefa <a class="header-anchor" href="#passo-3-verificar-conclusao-da-tarefa" aria-label="Permalink to &quot;Passo 3: Verificar Conclusão da Tarefa&quot;">​</a></h3><p>Depois que os agentes completarem, eles irão:</p><ol><li><strong>Mostrar evidências de verificação</strong>: Saída real de execução de testes, descrições de verificação manual</li><li><strong>Confirmar que todos os TODOs estão completos</strong>: Não declararão conclusão antecipadamente</li><li><strong>Resumir o trabalho realizado</strong>: Listar o que foi feito e por quê</li></ol><p><strong>Você deve ver</strong>:</p><ul><li>Resultados de testes claros (não &quot;deve funcionar&quot;)</li><li>Todos os problemas resolvidos</li><li>Nenhuma lista de TODO incompleta</li></ul><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de Verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de Verificação ✅&quot;">​</a></h2><p>Depois de completar os passos acima, confirme:</p><ul><li>[ ] Você vê uma notificação Toast após digitar <code>ulw</code></li><li>[ ] A resposta do agente começa com &quot;ULTRAWORK MODE ENABLED!&quot;</li><li>[ ] Você observa tarefas em segundo plano paralelas rodando</li><li>[ ] Os agentes usam o sistema Categoria + Skills</li><li>[ ] Há evidências de verificação após a conclusão da tarefa</li></ul><p>Se algum item falhar, verifique:</p><ul><li>A palavra-chave está escrita corretamente (<code>ultrawork</code> ou <code>ulw</code>)</li><li>Você está na sessão principal (tarefas em segundo plano não acionarão o modo)</li><li>O arquivo de configuração está ativado com recursos relevantes</li></ul><h2 id="quando-usar-esta-tecnica" tabindex="-1">Quando Usar Esta Técnica <a class="header-anchor" href="#quando-usar-esta-tecnica" aria-label="Permalink to &quot;Quando Usar Esta Técnica&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Cenário</th><th>Usar Ultrawork</th><th>Modo Normal</th></tr></thead><tbody><tr><td><strong>Recursos complexos novos</strong></td><td>✅ Recomendado (requer colaboração multi-agente)</td><td>❌ Pode não ser eficiente o suficiente</td></tr><tr><td><strong>Correções urgentes</strong></td><td>✅ Recomendado (precisa de diagnóstico rápido e exploração)</td><td>❌ Pode perder contexto</td></tr><tr><td><strong>Modificações simples</strong></td><td>❌ Exagerado (desperdiça recursos)</td><td>✅ Mais adequado</td></tr><tr><td><strong>Validação rápida de ideias</strong></td><td>❌ Exagerado</td><td>✅ Mais adequado</td></tr></tbody></table><p><strong>Regra prática</strong>:</p><ul><li>Tarefa envolve múltiplos módulos ou sistemas → Use <code>ulw</code></li><li>Precisa de pesquisa profunda da base de código → Use <code>ulw</code></li><li>Precisa chamar múltiplos agentes especializados → Use <code>ulw</code></li><li>Mudança pequena em arquivo único → Não precisa de <code>ulw</code></li></ul><h2 id="armadilhas-comuns" tabindex="-1">Armadilhas Comuns <a class="header-anchor" href="#armadilhas-comuns" aria-label="Permalink to &quot;Armadilhas Comuns&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Notas Importantes</p><p><strong>1. Não use <code>ulw</code> em todos os prompts</strong></p><p>O modo Ultrawork injeta uma grande quantidade de instruções, o que é exagerado para tarefas simples. Use-o apenas para tarefas complexas que realmente requerem colaboração multi-agente, exploração paralela e análise profunda.</p><p><strong>2. Tarefas em segundo plano não acionam o modo Ultrawork</strong></p><p>O detector de palavras-chave pula sessões em segundo plano para evitar injetar incorretamente o modo em sub-agentes. O modo Ultrawork só funciona na sessão principal.</p><p><strong>3. Garanta que a configuração do Provider esteja correta</strong></p><p>O modo Ultrawork depende de múltiplos modelos de IA trabalhando em paralelo. Se certos Providers não estiverem configurados ou indisponíveis, os agentes podem não conseguir chamar agentes especializados.</p></div><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>O modo Ultrawork alcança o objetivo de design de &quot;ativar todos os recursos com um comando&quot; através do acionamento por palavra-chave:</p><ul><li><strong>Fácil de usar</strong>: Basta digitar <code>ulw</code> para ativar</li><li><strong>Colaboração automática</strong>: Agentes chamam automaticamente outros agentes e executam tarefas em segundo plano em paralelo</li><li><strong>Conclusão forçada</strong>: Mecanismo de verificação completo garante 100% de conclusão</li><li><strong>Configuração zero</strong>: Não precisa definir manualmente prioridades de agentes, limites de concorrência, etc.</li></ul><p>Lembre-se: O modo Ultrawork é projetado para fazer os agentes trabalharem como uma equipe real. Você só precisa expressar a intenção, os agentes são responsáveis pela execução.</p><h2 id="proxima-licao" tabindex="-1">Próxima Lição <a class="header-anchor" href="#proxima-licao" aria-label="Permalink to &quot;Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos <strong><a href="./../../platforms/provider-setup/">Configuração de Provider</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como configurar múltiplos Providers como Anthropic, OpenAI, Google</li><li>Como a estratégia multi-modelo degrada automaticamente e seleciona modelos ótimos</li><li>Como testar conexões de Provider e uso de cota</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de Código Fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir locais de código fonte</strong></summary><blockquote><p>Última atualização: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Recurso</th><th>Caminho do Arquivo</th><th>Números de Linha</th></tr></thead><tbody><tr><td>Filosofia de design Ultrawork</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer"><code>docs/ultrawork-manifesto.md</code></a></td><td>1-198</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Template de instrução ULTRAWORK</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/constants.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/constants.ts</code></a></td><td>54-280</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Constantes principais</strong>:</p><ul><li><code>KEYWORD_DETECTORS</code>: Configuração do detector de palavras-chave, incluindo três modos: ultrawork, search, analyze</li><li><code>CODE_BLOCK_PATTERN</code>: Padrão regex de bloco de código, usado para filtrar palavras-chave em blocos de código</li><li><code>INLINE_CODE_PATTERN</code>: Padrão regex de código inline, usado para filtrar palavras-chave em código inline</li></ul><p><strong>Funções principais</strong>:</p><ul><li><code>createKeywordDetectorHook()</code>: Cria Hook de detector de palavras-chave, escuta evento UserPromptSubmit</li><li><code>detectKeywordsWithType()</code>: Detecta palavras-chave no texto e retorna tipo (ultrawork/search/analyze)</li><li><code>getUltraworkMessage()</code>: Gera instruções completas do modo ULTRAWORK (seleciona Planner ou modo normal baseado no tipo de agente)</li><li><code>removeCodeBlocks()</code>: Remove blocos de código do texto para evitar acionar palavras-chave em blocos de código</li></ul><p><strong>Regras de negócio</strong>:</p><table tabindex="0"><thead><tr><th>ID da Regra</th><th>Descrição da Regra</th><th>Tag</th></tr></thead><tbody><tr><td>BR-4.8.4-1</td><td>Ativar modo Ultrawork quando &quot;ultrawork&quot; ou &quot;ulw&quot; é detectado</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-2</td><td>Modo Ultrawork define <code>message.variant = &quot;max&quot;</code></td><td>[Fact]</td></tr><tr><td>BR-4.8.4-3</td><td>Modo Ultrawork exibe notificação Toast: &quot;Modo Ultrawork Ativado&quot;</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-4</td><td>Sessões de tarefas em segundo plano pulam detecção de palavras-chave para evitar injeção de modo</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-5</td><td>Sessões não principais só permitem palavra-chave ultrawork, bloqueando outras injeções de modo</td><td>[Fact]</td></tr></tbody></table></details>`,54)])])}const g=a(s,[["render",i]]);export{m as __pageData,g as default};
